class Solution {
    /**
     * Given a string s, return the number of occurrences of the substring "bob" in s.
     *
     * Example:
     * ----------
     * countBob("bobob") == 1
     * countBob("bob") == 1
     * countBob("bobbob") == 2
     *
     * Args:
     *     s (str): The input string.
     *
     * Returns:
     *     int: The number of occurrences of the substring "bob" in s.
     */
    public int countBob(String s) {
        int count = 0;
        for (int i = 0; i < s.length() - 2; i++) {
            if (s.substring(i, i + 3).equals("bob")) {
                count++;
            }
        }
        return count;
    }
